<script setup>
defineProps({ view:{type:Object,required:true}, busy:Boolean })
defineEmits(['choose','close'])
</script>
<template><div class="dialogue-backdrop" role="presentation" @click.self="$emit('close')"><section class="dialogue-overlay" role="dialog" aria-modal="true" aria-labelledby="dialogue-speaker"><header><div class="dialogue-portrait" aria-hidden="true">♟</div><div><small>{{ view.dialogueName }}</small><h2 id="dialogue-speaker">{{ view.speaker?.displayNameOverride || view.speaker?.speakerType || 'NPC' }}</h2></div><button type="button" aria-label="End conversation" @click="$emit('close')">×</button></header><div class="dialogue-text"><p>{{ view.text }}</p></div><footer><button v-for="row in view.choices" :key="row.choice.id" type="button" :disabled="busy || row.state !== 'Available'" @click="$emit('choose',row.choice.id)"><span>{{ row.choice.text }}</span><small v-if="row.costs?.length">{{ row.costs.map(c => `${c.quantity} ${c.type}`).join(' · ') }}</small><small v-if="row.disabledReason">{{ row.disabledReason }}</small></button></footer></section></div></template>
<style scoped>.dialogue-backdrop{position:fixed;inset:0;z-index:90;display:grid;place-items:center;background:#020617cc;padding:1rem}.dialogue-overlay{width:min(760px,96vw);max-height:90vh;overflow:auto;border:1px solid #64748b;border-radius:14px;background:#0f172a;color:#e2e8f0;box-shadow:0 24px 70px #000}.dialogue-overlay header{display:flex;align-items:center;gap:1rem;padding:1rem;border-bottom:1px solid #334155}.dialogue-overlay header div:nth-child(2){flex:1}.dialogue-overlay h2,.dialogue-overlay p{margin:0}.dialogue-portrait{display:grid;place-items:center;width:58px;height:58px;border:1px solid #94a3b8;border-radius:50%;font-size:2rem;background:#1e293b}.dialogue-overlay header button{font-size:1.4rem}.dialogue-text{min-height:150px;padding:1.5rem;font-size:1.08rem;line-height:1.7}.dialogue-overlay footer{display:grid;gap:.6rem;padding:1rem;border-top:1px solid #334155}.dialogue-overlay footer button{text-align:left;padding:.8rem 1rem;border:1px solid #64748b;border-radius:8px;background:#1e293b;color:#f8fafc}.dialogue-overlay footer button:hover:not(:disabled){border-color:#fbbf24;background:#273449}.dialogue-overlay footer button:disabled{opacity:.55}.dialogue-overlay small{display:block;color:#94a3b8}</style>
